/**
 * Docsify plugin that turns known type names inside TypeScript code blocks
 * into links to their documentation and shows the definition in a tooltip
 * on hover. The type name → link/definition map is generated by
 * packages/maintenance/src/docs/generateCCAPIs.ts.
 */
(function() {
	"use strict";

	let typeLinks;

	async function loadTypeLinks() {
		try {
			const response = await fetch("generated/type-links.json");
			typeLinks = response.ok ? await response.json() : null;
		} catch {
			// Docs work without type links, just without the extra comfort
			typeLinks = null;
		}
	}

	const IDENTIFIER = /[$A-Za-z_][$\w]*/g;
	const DECLARATION_NAME =
		/\b(?:enum|interface|type|class)\s+([$A-Za-z_][$\w]*)/g;

	function linkifyCodeBlock(code) {
		const walker = document.createTreeWalker(
			code,
			NodeFilter.SHOW_TEXT,
		);
		// Track each text node's offset in the full code text: syntax
		// highlighting splits keywords and identifiers into separate nodes
		const fullText = code.textContent;
		// A type name directly after a declaration keyword is its own
		// definition and must not link to itself
		const declarationNameOffsets = new Set();
		for (const match of fullText.matchAll(DECLARATION_NAME)) {
			declarationNameOffsets.add(
				match.index + match[0].length - match[1].length,
			);
		}
		const textNodes = [];
		let offset = 0;
		let node;
		while ((node = walker.nextNode())) {
			textNodes.push({ node: node, offset: offset });
			offset += node.nodeValue.length;
		}

		for (const entry of textNodes) {
			const textNode = entry.node;
			if (textNode.parentElement && textNode.parentElement.closest("a")) {
				continue;
			}
			const text = textNode.nodeValue;
			let lastIndex = 0;
			let fragment;

			for (const match of text.matchAll(IDENTIFIER)) {
				const name = match[0];
				const target = typeLinks[name];
				if (!target) continue;
				if (declarationNameOffsets.has(entry.offset + match.index)) {
					continue;
				}

				fragment ??= document.createDocumentFragment();
				if (match.index > lastIndex) {
					fragment.appendChild(
						document.createTextNode(
							text.slice(lastIndex, match.index),
						),
					);
				}
				const link = document.createElement("a");
				link.className = "type-link";
				link.href = target.href;
				link.textContent = name;
				if (target.definition || target.description) {
					link.dataset.typeName = name;
				}
				fragment.appendChild(link);
				lastIndex = match.index + name.length;
			}

			if (fragment) {
				if (lastIndex < text.length) {
					fragment.appendChild(
						document.createTextNode(text.slice(lastIndex)),
					);
				}
				textNode.replaceWith(fragment);
			}
		}
	}

	let tooltip;

	function getTooltip() {
		if (!tooltip) {
			tooltip = document.createElement("div");
			tooltip.className = "type-link-tooltip";
			tooltip.style.display = "none";
			document.body.appendChild(tooltip);
			// Keep the tooltip open while the cursor is over it, e.g. to scroll
			tooltip.addEventListener("mouseleave", hideTooltip);
		}
		return tooltip;
	}

	function escapeHtml(text) {
		return text
			.replaceAll("&", "&amp;")
			.replaceAll("<", "&lt;")
			.replaceAll(">", "&gt;");
	}

	// The tooltip lives outside .markdown-section, so it does not inherit the
	// theme's tab width; copy it from a real code block so its indentation
	// matches the rendered code on the page. Constant per rendered page, so
	// it is computed once in doneEach instead of on every hover.
	let codeTabSize = "";

	function showTooltip(link) {
		const name = link.dataset.typeName;
		const entry = typeLinks[name];
		if (!entry) return;
		const definition = entry.definition;
		const description = entry.description;
		if (!definition && !description) return;

		const el = getTooltip();
		let inner = "";
		if (description) {
			inner += "<p class=\"type-link-tooltip-desc\">"
				+ escapeHtml(description)
				+ "</p>";
		}
		if (definition) {
			let html;
			if (
				window.Prism
				&& window.Prism.languages
				&& window.Prism.languages.typescript
			) {
				html = window.Prism.highlight(
					definition,
					window.Prism.languages.typescript,
					"typescript",
				);
			} else {
				html = escapeHtml(definition);
			}
			inner += "<pre style=\"tab-size:"
				+ codeTabSize
				+ "\"><code>"
				+ html
				+ "</code></pre>";
		}
		el.innerHTML = inner;

		const rect = link.getBoundingClientRect();
		el.style.display = "block";
		// Measure after making it visible, then clamp to the viewport
		const width = Math.min(el.offsetWidth, window.innerWidth - 20);
		const left = Math.min(
			rect.left + window.scrollX,
			window.scrollX + window.innerWidth - width - 10,
		);
		let top = rect.bottom + window.scrollY + 6;
		if (
			rect.bottom + el.offsetHeight + 6 > window.innerHeight
			&& rect.top - el.offsetHeight - 6 > 0
		) {
			top = rect.top + window.scrollY - el.offsetHeight - 6;
		}
		el.style.left = left + "px";
		el.style.top = top + "px";
	}

	function hideTooltip() {
		if (tooltip) tooltip.style.display = "none";
	}

	function handleMouseOver(event) {
		const link = event.target.closest("a.type-link[data-type-name]");
		if (link) showTooltip(link);
	}

	function handleMouseOut(event) {
		const link = event.target.closest("a.type-link[data-type-name]");
		if (!link) return;
		// Moving onto the tooltip itself keeps it open
		if (
			event.relatedTarget
			&& tooltip
			&& tooltip.contains(event.relatedTarget)
		) {
			return;
		}
		hideTooltip();
	}

	// Keyboard users reach the links by tab, so mirror the hover preview on focus
	function handleFocusIn(event) {
		const link = event.target.closest("a.type-link[data-type-name]");
		if (link) showTooltip(link);
	}

	function handleFocusOut(event) {
		const link = event.target.closest("a.type-link[data-type-name]");
		if (link) hideTooltip();
	}

	function install(hook) {
		hook.mounted(function() {
			document.body.addEventListener("mouseover", handleMouseOver);
			document.body.addEventListener("mouseout", handleMouseOut);
			document.body.addEventListener("focusin", handleFocusIn);
			document.body.addEventListener("focusout", handleFocusOut);
		});

		hook.doneEach(async function() {
			if (typeLinks === undefined) await loadTypeLinks();
			if (!typeLinks) return;
			hideTooltip();
			const codeBlocks = document.querySelectorAll(
				".markdown-section pre[data-lang='ts'] code",
			);
			codeTabSize = codeBlocks.length
				? getComputedStyle(codeBlocks[0]).tabSize
				: "";
			for (const code of codeBlocks) {
				linkifyCodeBlock(code);
			}
		});
	}

	window.$docsify = window.$docsify || {};
	window.$docsify.plugins = (window.$docsify.plugins || []).concat(install);
})();
